            //
            aOrbiterJ = ((aOrbiterJ + aOrbiterE) + 0xD9348DF13AA11ADEULL) + aPhaseEOrbiterUpdateSaltC[((aIndex + 10U)) & S_SALT1];
            aOrbiterC = (aOrbiterC ^ aOrbiterJ) ^ 0x190656757347C3A9ULL;
            aOrbiterC = RotL64((aOrbiterC * 0xA429880CB079E31FULL), 41U);
            //
            aOrbiterF = ((aOrbiterF + aOrbiterI) + 0x5E7903A86AD604C8ULL) + aPhaseEOrbiterUpdateSaltE[(((31U - aIndex) + 14U)) & S_SALT1];
            aOrbiterE = (aOrbiterE ^ aOrbiterF) ^ 0xC4D5749B3F220766ULL;
