            //
            aOrbiterC = ((aOrbiterC + aOrbiterH) + 0xBFAE664FCEBAF95EULL) + aPhaseEOrbiterUpdateSaltA[((aIndex + 11U)) & S_SALT1];
            aOrbiterF = (aOrbiterF ^ aOrbiterC) ^ 0x55CB708986B2F3CEULL;
            aOrbiterF = RotL64((aOrbiterF * 0x2AECA87CB4D8B4CFULL), 3U);
            //
