            //
            aWandererH = aWandererH ^ (((RotL64(aPrevious, 6U) + RotL64(aOrbiterE, 60U)) + aOrbiterJ) + aPhaseEWandererUpdateSaltF[(((31U - aIndex) + 26U)) & S_SALT1]);
            aWandererK = aWandererK + (((RotL64(aScatter, 35U) + aOrbiterH) + RotL64(aOrbiterJ, 5U)) + aPhaseEWandererUpdateSaltC[(((31U - aIndex) + 17U)) & S_SALT1]);
            aWandererG = aWandererG ^ ((RotL64(aCross, 21U) + RotL64(aOrbiterI, 35U)) + aOrbiterC);
            aWandererJ = aWandererJ + (((RotL64(aIngress, 41U) + aOrbiterK) + RotL64(aOrbiterF, 53U)) + RotL64(aCarry, 5U));
