            //
            aOrbiterD = (aWandererB + RotL64(aScatter, 54U)) + 0x47260A28852A27C8ULL;
            aOrbiterA = ((aWandererK + RotL64(aPrevious, 41U)) + RotL64(aCarry, 29U)) + 0xF77141663E886B60ULL;
            aOrbiterH = (aWandererC + RotL64(aIngress, 5U)) + 0xA0462EA480C75B75ULL;
            aOrbiterB = (aWandererH + RotL64(aCross, 43U)) + 0x3215A932A4976EE3ULL;
            aOrbiterJ = (aWandererG + RotL64(aScatter, 39U)) + 0xC15B173489DFD4E1ULL;
            aOrbiterE = ((aWandererD + RotL64(aPrevious, 13U)) + 0xDA96368E9E59A12AULL) + aPhaseCOrbiterAssignSaltF[(((31U - aIndex) + 13U)) & S_SALT1];
            aOrbiterF = (aWandererA + RotL64(aCross, 26U)) + 0x3F7EA36F85126A93ULL;
            aOrbiterG = (aWandererI + RotL64(aIngress, 35U)) + 0x70363072B6DAF661ULL;
            aOrbiterI = ((aWandererJ + RotL64(aScatter, 3U)) + RotL64(aCarry, 53U)) + 0xD83BA3246E57D6EAULL;
            aOrbiterC = ((aWandererF + RotL64(aCross, 23U)) + RotL64(aCarry, 57U)) + 0xCB39D44AEFE5CF35ULL;
            aOrbiterK = ((aWandererE + RotL64(aIngress, 11U)) + 0x60A4625B9AB822C9ULL) + aPhaseCOrbiterAssignSaltD[((aIndex + 8U)) & S_SALT1];
            //
            aOrbiterD = (aOrbiterD + aOrbiterA) + 0xAC19825985CDBECCULL;
            aOrbiterH = (aOrbiterH ^ aOrbiterD) ^ 0x7931B5BF576FB3D4ULL;
