            //
            aOrbiterB = (aOrbiterB + aOrbiterD) + 0x3CA51F13C20EF8FEULL;
            aOrbiterJ = ((aOrbiterJ ^ aOrbiterB) ^ 0x6CA2C627CC16AAD8ULL) ^ aPhaseCOrbiterUpdateSaltB[(((31U - aIndex) + 20U)) & S_SALT1];
            aOrbiterJ = RotL64((aOrbiterJ * 0x47DFD19327196707ULL), 29U);
            //
            aOrbiterE = (aOrbiterE + aOrbiterJ) + 0x77CF238F56A87642ULL;
            aOrbiterF = (aOrbiterF ^ aOrbiterE) ^ 0xA57127A7F1305AABULL;
            aOrbiterF = RotL64((aOrbiterF * 0x6FA8CEF136B96825ULL), 13U);
            //
            aOrbiterJ = ((aOrbiterJ + aOrbiterH) + 0x3626CED4351AC138ULL) + aPhaseCOrbiterUpdateSaltE[(((31U - aIndex) + 11U)) & S_SALT1];
            aOrbiterG = (aOrbiterG ^ aOrbiterJ) ^ 0xC615F8428F4A31BCULL;
            aOrbiterG = RotL64((aOrbiterG * 0x1EEAB28202D26139ULL), 19U);
            //
            aOrbiterF = ((aOrbiterF + aOrbiterG) + 0x2A53C7AC97D5A073ULL) + aPhaseCOrbiterUpdateSaltD[((aIndex + 26U)) & S_SALT1];
            aOrbiterB = (aOrbiterB ^ aOrbiterF) ^ 0xEDF0BA85E15559FCULL;
            aOrbiterB = RotL64((aOrbiterB * 0xA10ADBC8219E7467ULL), 53U);
            //
            aOrbiterI = (aOrbiterI + aOrbiterB) + 0xC6AFE22C821A0DAFULL;
            aOrbiterE = (aOrbiterE ^ aOrbiterI) ^ 0x719F2B4F3753092CULL;
            aOrbiterE = RotL64((aOrbiterE * 0x8B120DA581628519ULL), 35U);
            //
            aOrbiterG = (aOrbiterG + aOrbiterC) + 0xF19A1A257BD9CB70ULL;
            aOrbiterD = (aOrbiterD ^ aOrbiterG) ^ 0xE70BB7F687D21F82ULL;
            aOrbiterD = RotL64((aOrbiterD * 0x89AAE53A44F45939ULL), 5U);
            //
            aOrbiterA = (aOrbiterA + aOrbiterE) + 0xACC8E3B4763082E0ULL;
            aOrbiterK = ((aOrbiterK ^ aOrbiterA) ^ 0x121F26DCA14A9F2DULL) ^ aPhaseCOrbiterUpdateSaltF[(((31U - aIndex) + 14U)) & S_SALT1];
            aOrbiterK = RotL64((aOrbiterK * 0xF4511240B1E8AFD9ULL), 27U);
            //
            aOrbiterC = (aOrbiterC + aOrbiterI) + 0xD122241BCA6CB8B3ULL;
            aOrbiterA = (aOrbiterA ^ aOrbiterC) ^ 0x7CB3F792CEEAC5D7ULL;
