            //
            aOrbiterK = (aOrbiterK + aOrbiterF) + 0xA0984A264F3D1E17ULL;
            aOrbiterI = (aOrbiterI ^ aOrbiterK) ^ 0x08344106F7194E52ULL;
            aOrbiterI = RotL64((aOrbiterI * 0x56AA6B568BA7B297ULL), 21U);
            //
            aOrbiterH = (aOrbiterH + aOrbiterK) + 0xB7412D0B1D4AABBDULL;
            aOrbiterC = (aOrbiterC ^ aOrbiterH) ^ 0x861465F3FA199ACCULL;
