            aWandererH = aWandererH ^ (((RotL64(aCross, 11U) + aOrbiterE) + RotL64(aOrbiterG, 47U)) + aPhaseDWandererUpdateSaltF[((aIndex + 9U)) & S_SALT1]);
            aWandererK = aWandererK + (((RotL64(aIngress, 3U) + RotL64(aOrbiterJ, 19U)) + aOrbiterA) + aPhaseDWandererUpdateSaltE[((aIndex + 29U)) & S_SALT1]);
            aWandererI = aWandererI ^ ((RotL64(aScatter, 28U) + aOrbiterB) + RotL64(aOrbiterJ, 43U));
            aWandererC = aWandererC + (((RotL64(aIngress, 41U) + aOrbiterC) + RotL64(aOrbiterG, 23U)) + RotL64(aCarry, 41U));
            aWandererG = aWandererG ^ ((RotL64(aScatter, 47U) + aOrbiterJ) + RotL64(aOrbiterI, 54U));
