            aOrbiterA = RotL64((aOrbiterA * 0x96E41042A6C84949ULL), 47U);
            //
            aOrbiterA = ((aOrbiterA + aOrbiterF) + 0x41D44B2F42452F85ULL) + aPhaseGOrbiterUpdateSaltE[(((31U - aIndex) + 7U)) & S_SALT1];
            aOrbiterI = (aOrbiterI ^ aOrbiterA) ^ 0x1CF7C34CB914F59FULL;
            aOrbiterI = RotL64((aOrbiterI * 0x5BD24B844AA259D7ULL), 27U);
            //
            aOrbiterH = (aOrbiterH + aOrbiterG) + 0x52FDCE0F3245B171ULL;
            aOrbiterK = (aOrbiterK ^ aOrbiterH) ^ 0x6B9EA71DFC3C05C4ULL;
            aOrbiterK = RotL64((aOrbiterK * 0x35D5BDB37E39F62FULL), 51U);
            //
            aOrbiterE = (aOrbiterE + aOrbiterJ) + 0xC8AA290AED372F3DULL;
            aOrbiterG = (aOrbiterG ^ aOrbiterE) ^ 0xB15B988911B635ECULL;
            aOrbiterG = RotL64((aOrbiterG * 0x175393BCD30BCBD9ULL), 43U);
            //
            aOrbiterF = (aOrbiterF + aOrbiterK) + 0xF8771D5A2F4E7826ULL;
            aOrbiterB = (aOrbiterB ^ aOrbiterF) ^ 0xE817026A46163837ULL;
            aOrbiterB = RotL64((aOrbiterB * 0xD4345A7B13182C0DULL), 37U);
            //
            aOrbiterG = (aOrbiterG + aOrbiterA) + 0xB022F3BEEA924263ULL;
            aOrbiterC = ((aOrbiterC ^ aOrbiterG) ^ 0x86FDDB032D91EDEEULL) ^ aPhaseGOrbiterUpdateSaltA[((aIndex + 9U)) & S_SALT1];
            aOrbiterC = RotL64((aOrbiterC * 0xEFC5DEC373315C35ULL), 53U);
            //
            aOrbiterB = (aOrbiterB + aOrbiterE) + 0x9C9C8EDC73A286AAULL;
            aOrbiterH = ((aOrbiterH ^ aOrbiterB) ^ 0x886E3880E1E186CEULL) ^ aPhaseGOrbiterUpdateSaltB[(((31U - aIndex) + 5U)) & S_SALT1];
