            //
            aOrbiterC = ((aOrbiterC + aOrbiterI) + 0xD4198144BD356132ULL) + aPhaseGOrbiterUpdateSaltF[((aIndex + 16U)) & S_SALT1];
            aOrbiterJ = (aOrbiterJ ^ aOrbiterC) ^ 0x6768F1779D9B8BEDULL;
