            aIngress = TwistMix64::DiffuseC((aIngress + aScatter));
            //
            aWandererJ = aWandererJ + ((RotL64(aIngress, 41U) + aOrbiterC) + RotL64(aOrbiterI, 53U));
            aWandererC = aWandererC ^ ((RotL64(aCross, 19U) + aOrbiterK) + RotL64(aOrbiterE, 21U));
            aWandererA = aWandererA + ((RotL64(aScatter, 47U) + aOrbiterH) + RotL64(aOrbiterG, 43U));
            aWandererF = aWandererF ^ ((RotL64(aPrevious, 39U) + RotL64(aOrbiterH, 60U)) + aOrbiterF);
            aWandererK = aWandererK + (((RotL64(aCross, 60U) + aOrbiterB) + RotL64(aOrbiterJ, 39U)) + RotL64(aCarry, 51U));
