            //
            aOrbiterG = ((aOrbiterG + aOrbiterB) + 0x023DB5EAF68C70A6ULL) + aPhaseHOrbiterUpdateSaltF[((aIndex + 25U)) & S_SALT1];
            aOrbiterC = (aOrbiterC ^ aOrbiterG) ^ 0x7BFB9E3C506077A8ULL;
            aOrbiterC = RotL64((aOrbiterC * 0xE46896950E284B2DULL), 13U);
