            aOrbiterK = (aOrbiterK + aOrbiterH) + 0xCC376C9A3D6E15B4ULL;
            aOrbiterD = (aOrbiterD ^ aOrbiterK) ^ 0x7B7D9B8E5F376064ULL;
            aOrbiterD = RotL64((aOrbiterD * 0xE9E52746CA5AE713ULL), 43U);
            //
            aOrbiterC = (aOrbiterC + aOrbiterF) + 0xF508D6B19AC0E6C3ULL;
            aOrbiterE = (aOrbiterE ^ aOrbiterC) ^ 0x06258D0C2EDBB0E1ULL;
            aOrbiterE = RotL64((aOrbiterE * 0x9092D59B465E29EFULL), 47U);
            //
            aOrbiterB = ((aOrbiterB + aOrbiterD) + 0x2DA33364A5861CB7ULL) + aPhaseHOrbiterUpdateSaltA[(((31U - aIndex) + 26U)) & S_SALT1];
            aOrbiterF = ((aOrbiterF ^ aOrbiterB) ^ 0xB268922B0E85161FULL) ^ aPhaseHOrbiterUpdateSaltD[(((31U - aIndex) + 9U)) & S_SALT1];
            aOrbiterF = RotL64((aOrbiterF * 0x5353F5839AE32181ULL), 23U);
            //
            aOrbiterH = (aOrbiterH + aOrbiterE) + 0x65ACFE515471D693ULL;
            aOrbiterG = (aOrbiterG ^ aOrbiterH) ^ 0x5E14FC1463E8A9D8ULL;
            aOrbiterG = RotL64((aOrbiterG * 0xDD39FB892D19B1D9ULL), 51U);
            //
            aOrbiterI = (aOrbiterI + aOrbiterC) + 0x78CE0FCED1DCA2C4ULL;
