            //
            aOrbiterE = (aOrbiterE + aOrbiterK) + 0x684D7BEE3238F256ULL;
            aOrbiterB = ((aOrbiterB ^ aOrbiterE) ^ 0x7C2048D012CB95DEULL) ^ aPhaseHOrbiterUpdateSaltB[(((31U - aIndex) + 3U)) & S_SALT1];
            aOrbiterB = RotL64((aOrbiterB * 0xD3C1ED6B960ABC1DULL), 27U);
            //
            aIngress = RotL64(aOrbiterH, 37U) ^ aOrbiterG;
