            aWandererI = aWandererI + (((RotL64(aCross, 38U) + aOrbiterE) + RotL64(aOrbiterK, 35U)) + RotL64(aCarry, 41U));
            aWandererC = aWandererC ^ ((RotL64(aScatter, 13U) + aOrbiterD) + RotL64(aOrbiterB, 43U));
